def decompose_number(n):
    if n == 0:
        return ""

    digits = str(n)
    length = len(digits)
    result = []

    for i, digit in enumerate(digits):
        if digit != '0':
            power_of_ten = length - i - 1
            if power_of_ten == 0:
                result.append(f"{digit}")
            else:
                result.append(f"{digit}*10^{power_of_ten}")

    return '+'.join(result)

