def getAllPrimeFactors(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    factors = []
    factor = 2
    while factor * factor <= n:
        while n % factor == 0:
            factors.append(factor)
            n //= factor
        factor += 1
    if n > 1:
        factors.append(n)
    return factors

def getUniquePrimeFactorsWithCount(n):
    if not isinstance(n, int) or n <= 0:
        return [[], []]
    if n == 1:
        return [[1], [1]]
    unique_factors = []
    counts = []
    factor = 2
    while factor * factor <= n:
        count = 0
        while n % factor == 0:
            count += 1
            n //= factor
        if count > 0:
            unique_factors.append(factor)
            counts.append(count)
        factor += 1
    if n > 1:
        unique_factors.append(n)
        counts.append(1)
    return [unique_factors, counts]

def getUniquePrimeFactorsWithProducts(n):
    if not isinstance(n, int) or n <= 0:
        return []
    if n == 1:
        return [1]
    unique_factors, counts = getUniquePrimeFactorsWithCount(n)
    products = [factor ** count for factor, count in zip(unique_factors, counts)]
    return products

