def find_element_to_remove(arr):
    # Calculate the total product of the array
    total_product = 1
    zero_count = 0
    for num in arr:
        if num != 0:
            total_product *= num
        else:
            zero_count += 1

    # If there are more than one zero, the product will always be zero
    if zero_count > 1:
        return 0

    max_product = float('-inf')
    element_to_remove = None

    for num in arr:
        if num == 0:
            # If there's only one zero, removing it will maximize the product
            product_without_num = total_product
        else:
            product_without_num = total_product // num

        if product_without_num > max_product:
            max_product = product_without_num
            element_to_remove = num
        elif product_without_num == max_product:
            # If the product is the same, choose the smallest element
            if element_to_remove is None or num < element_to_remove:
                element_to_remove = num

    return element_to_remove

