def solve_expression(expression):
    import re

    # Split the expression into left and right parts
    left, right = expression.split('=')

    # Find the operator in the left part
    match = re.search(r'[\+\-\*]', left)
    if not match:
        return -1

    op_index = match.start()
    operator = left[op_index]

    # Split the left part into two numbers
    num1 = left[:op_index]
    num2 = left[op_index+1:]

    # Function to check if a number is valid
    def is_valid_number(s):
        if len(s) > 1 and s[0] == '0':
            return False
        if len(s) > 1 and s[0] == '-' and s[1] == '0':
            return False
        return True

    # Try each digit from 0 to 9
    for digit in range(10):
        if str(digit) in expression:
            continue

        # Replace '?' with the current digit
        test_num1 = num1.replace('?', str(digit))
        test_num2 = num2.replace('?', str(digit))
        test_right = right.replace('?', str(digit))

        # Check if all numbers are valid
        if not (is_valid_number(test_num1) and is_valid_number(test_num2) and is_valid_number(test_right)):
            continue

        # Evaluate the expression
        try:
            if operator == '+':
                if int(test_num1) + int(test_num2) == int(test_right):
                    return digit
            elif operator == '-':
                if int(test_num1) - int(test_num2) == int(test_right):
                    return digit
            elif operator == '*':
                if int(test_num1) * int(test_num2) == int(test_right):
                    return digit
        except ValueError:
            continue

    return -1

