def count_factorizations(n, k):
    def backtrack(remaining, k, start):
        if k == 1:
            return 1 if remaining >= start else 0
        count = 0
        for i in range(start, remaining + 1):
            if remaining % i == 0:
                count += backtrack(remaining // i, k - 1, i)
        return count

    return backtrack(n, k, 1)

