def minimum_cost_to_connect_employees(n, m, employees_languages):
    parent = list(range(n))
    rank = [1] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        rootX = find(x)
        rootY = find(y)
        if rootX != rootY:
            if rank[rootX] > rank[rootY]:
                parent[rootY] = rootX
            elif rank[rootX] < rank[rootY]:
                parent[rootX] = rootY
            else:
                parent[rootY] = rootX
                rank[rootX] += 1

    # Map each language to the list of employees who know it
    language_to_employees = {}
    for i, languages in enumerate(employees_languages):
        for lang in languages:
            if lang not in language_to_employees:
                language_to_employees[lang] = []
            language_to_employees[lang].append(i)

    # Union employees who share a common language
    for employees in language_to_employees.values():
        for i in range(1, len(employees)):
            union(employees[0], employees[i])

    # Count the number of connected components
    components = len(set(find(i) for i in range(n)))

    # If all employees know no languages, we need to connect them all
    if all(len(languages) == 0 for languages in employees_languages):
        return n

    # Minimum cost is the number of additional connections needed
    return components - 1

