    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    def cell_id(r, c):
        return r * n + c

    def is_valid(r, c):
        return 0 <= r < 2 and 0 <= c < n

    # Initially connect all cells in the first row and second row
    for c in range(n - 1):
        uf.union(cell_id(0, c), cell_id(0, c + 1))
