def solve_parking_lot(n, k, grid):
    # Directions for moving cars: right, left, down, up
    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]

    # Initial state
    initial_state = tuple(tuple(row) for row in grid)

    # Queue for BFS: (current state, moves list)
    queue = deque([(initial_state, [])])
    visited = {initial_state}

    def is_valid(r, c):
        return 0 <= r < 4 and 0 <= c < n

    def is_parking_spot(r, c, car):
        return (r == 0 and grid[r][c] == car) or (r == 3 and grid[r][c] == car)

    while queue:
        state, moves = queue.popleft()

        # Check if all cars are parked
        all_parked = True
        for r in range(1, 3):
            for c in range(n):
                if state[r][c] != 0:
                    all_parked = False
                    break
            if not all_parked:
                break

        if all_parked:
            print(len(moves))
            for move in moves:
                print(*move)
            return

        # Try moving each car
        for r in range(1, 3):
            for c in range(n):
                car = state[r][c]
                if car == 0:
                    continue

                # Try moving the car in all directions
                for dr, dc in directions:
                    nr, nc = r + dr, c + dc
                    if is_valid(nr, nc) and state[nr][nc] == 0:
                        # Create a new state
                        new_state = [list(row) for row in state]
                        new_state[r][c], new_state[nr][nc] = new_state[nr][nc], new_state[r][c]
                        new_state_tuple = tuple(tuple(row) for row in new_state)

                        if new_state_tuple not in visited:
                            visited.add(new_state_tuple)
                            new_moves = moves + [(car, nr + 1, nc + 1)]
                            queue.append((new_state_tuple, new_moves))

    print(-1)

