def lucky_permutation(n):
    if n == 1:
        return [1]
    if n == 2:
        return -1

    permutation = list(range(1, n + 1))

    for i in range(0, n - 1, 2):
        permutation[i], permutation[i + 1] = permutation[i + 1], permutation[i]

    return permutation

